// (icmp ult (add a, b), a) | (icmp ult (add a, b), b) -> icmp ult (add a, b), a
// (icmp uge (add a, b), a) & (icmp uge (add a, b), b) -> icmp uge (add a, b), a
// For unsigned addition, overflow occurs iff sum < either operand.
// Similarly, no-overflow (sum >= either operand) conditions are equivalent.
static Value *simplifyOrOfICmpsWithAddOverflow(ICmpInst *Op0, ICmpInst *Op1) {
  ICmpInst::Predicate Pred0;
  Value *Add;
  Value *A, *B;

  // Try to match: icmp Pred0 Add, A (Add is first operand)
  if (!match(Op0, m_ICmp(Pred0, m_Value(Add), m_Value(A)))) {
    // Try to match: icmp Pred0 A, Add (Add is second operand, sum is compared as larger)
    if (!match(Op0, m_ICmp(Pred0, m_Value(A), m_Value(Add))))
      return nullptr;
  }

  // Check if Add is (add A, B).
  if (!match(Add, m_Add(m_Specific(A), m_Value(B))))
    return nullptr;

  // Check if Op1 is an icmp with the same Add.
  ICmpInst::Predicate Pred1;
  if (!match(Op1, m_ICmp(Pred1, m_Specific(Add), m_Value())))
    return nullptr;

  // Get the second operand of Op1's icmp
  Value *Op1RHS = Op1->getOperand(1);

  // For unsigned add overflow: sum < a means overflow, and sum < b is equivalent
  // For unsigned add no-overflow: sum >= a means no overflow, and sum >= b is equivalent
  auto isMatchingPreds = [](CmpInst::Predicate P0, CmpInst::Predicate P1) {
    // Both ult or both ugt (overflow detection)
    if ((P0 == CmpInst::ICMP_ULT || P0 == CmpInst::ICMP_UGT) &&
        (P1 == CmpInst::ICMP_ULT || P1 == CmpInst::ICMP_UGT))
      return true;
    // Both uge or both ule (no-overflow detection)  
    if ((P0 == CmpInst::ICMP_UGE || P0 == CmpInst::ICMP_ULE) &&
        (P1 == CmpInst::ICMP_UGE || P1 == CmpInst::ICMP_ULE))
      return true;
    return false;
  };

  if (!isMatchingPreds(Pred0, Pred1))
    return nullptr;

  // Check that Op1 compares Sum with B
  // For ult/uge: Sum is first operand
  // For ugt/ule: Sum is second operand
  auto isSumFirst = [](CmpInst::Predicate P) {
    return P == CmpInst::ICMP_ULT || P == CmpInst::ICMP_UGE;
  };

  // Verify Op1 compares Add with B
  bool Op1IsSumB = (isSumFirst(Pred1) && Op1->getOperand(1) == B) ||
                   (!isSumFirst(Pred1) && Op1->getOperand(0) == B);
  if (!Op1IsSumB)
    return nullptr;

  return Op0;
}
ENDFIX"}

